sql:
SELECT team_size 
FROM project_teams 
WHERE team_rep = 'O. Hill';

SELECT AVG(STRFTIME('%Y', 'now') - STRFTIME('%Y', created_at)) AS average_age
FROM projects
WHERE status = 'Completed';

SELECT MAX(percent_completed)
FROM projects
WHERE status = 'Completed';

SELECT DISTINCT p1.project_name, p1.budget_approved
FROM projects p1
JOIN projects p2 ON p1.budget_approved = p2.budget_approved AND p1.project_id != p2.project_id;

SELECT DISTINCT contractor
FROM projects
WHERE ward = (SELECT ward FROM projects WHERE project_name = 'FedAid') AND contractor IS NOT NULL;

SELECT projects.project_name, projects.contractor, project_teams.team_rep
FROM projects
LEFT JOIN project_teams ON projects.project_id = project_teams.project_id;

external_knowledge:
- "main quadrants of the city" implies NW, NE, SW, SE; 
- "budgeted for after the turn of the century" means the year budgeted is greater than 2000; 
- "team bigger than just a handful" implies the team size is more than 5 members; 
- "team longevity" refers to the time span between the creation and the last update of the team record.

sql:
SELECT SUM(percent_completed) AS total_completion_percentage
FROM projects
WHERE year_budgeted = 2004 AND status = 'Completed';

SELECT project_name, supervisor, contractor 
FROM projects 
WHERE priority_level IN ('High', 'Medium');
